-- 自動生成: 厚労省オープンデータ → clinics 投入用SQL
-- Supabase ダッシュボード → SQL Editor に貼って Run（schema.sql 実行後）

on conflict (external_id) do update set
  name=excluded.name, address=excluded.address, prefecture=excluded.prefecture,
  city=excluded.city, business_hours=excluded.business_hours, hours=excluded.hours,
  lat=excluded.lat, lng=excluded.lng, source=excluded.source;
